package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelManager;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorDataManager;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorDataManagerFactory;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandler;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorService;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ControlesRekenResultatenService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.service.ControleAgendaService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.lpb.tools.service.WachtAgendaService;
import be.schaubroeck.temporal.interval.LocalDateInterval;

import java.util.HashSet;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ACTOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ARTIKELMOTOR_DATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BOEK_DATUM_INTERVALLEN_SET_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENMODUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_FEEDBACK_KEY;

public class MetArtikelResultaatHandlerImp extends ResultaatHandlerImp {

    private ArtikelMotorService artikelMotorService;
    private ArtikelMotorResultaatHandler artikelHandler;
    private ArtikelManager artikelManager;
    private ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory;

    public MetArtikelResultaatHandlerImp(
            RekenResultatenService rekenResultatenService, WachtAgendaService wachtAgendaService,
            RegulAgendaService regulAgendaService, ArtikelMotorService artikelMotorService, ArtikelMotorResultaatHandler artikelHandler,
            ArtikelManager artikelManager, ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory, ControleAgendaService controleAgendaService,
            ControlesRekenResultatenService controlesRekenResultatenService) {
        super(rekenResultatenService, wachtAgendaService, regulAgendaService, controleAgendaService, controlesRekenResultatenService);
        this.artikelMotorService = artikelMotorService;
        this.artikelHandler = artikelHandler;
        this.artikelManager = artikelManager;
        this.artikelMotorDataManagerFactory = artikelMotorDataManagerFactory;

    }

    @Override
    public void verwerkResultaten(Admin admin, RekenContext mainContext) {
        super.verwerkResultaten(admin, mainContext);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        RekenFeedback feedback = mainContext.getUnchecked(REKEN_FEEDBACK_KEY);
        ArtikelMotorDataManager dataManager = mainContext.getUnchecked(ARTIKELMOTOR_DATA_MANAGER_KEY);
        String actor = mainContext.getUnchecked(ACTOR_KEY);
        Set<LocalDateInterval> boekDatumIntervallen = mainContext.getUnchecked(BOEK_DATUM_INTERVALLEN_SET_KEY);
        if (boekDatumIntervallen == null) {
            boekDatumIntervallen = new HashSet<>();
        }
        if (dataManager == null) {
            dataManager = artikelMotorDataManagerFactory
                    .create(admin, persoon.getId(), getOpdrachtNrs(persoon), boekDatumIntervallen, rekenTijd, artikelManager);
        }

        Rekenmodus rekenModus = mainContext.getUnchecked(REKENMODUS_KEY);

        artikelMotorService.koppelOpdrachtArtikels(admin, dataManager, rekenTijd, rekenModus, artikelHandler, regulManager, feedback, actor);
    }

    private Set<Integer> getOpdrachtNrs(Persoon persoon) {
        Set<Integer> opdrachtNrs = new HashSet<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            opdrachtNrs.add(opdracht.getOpdrachtnr());
        }
        return opdrachtNrs;
    }

}
